#include <vector>
#include <queue>
#include <tuple>
#include <climits>
#include <algorithm>

using namespace std;

// Define a state for the priority queue: {time, r, c, color}
// We want a min-heap based on time.
using State = tuple<long long, long long, long long, long long>;

// Custom comparator for the min-heap
struct CompareState {
    bool operator()(const State& a, const State& b) {
        // Priority queue in C++ STL is a max-heap.
        // To make it a min-heap based on time (first element), 
        // we return true if a has a larger time than b.
        return get<0>(a) > get<0>(b);
    }
};

std::vector<std::vector<long long>> solve(long long n, long long m, std::vector<std::vector<long long>> sources) {

    // Initialize distance (time) to a very large number
    // Since N*M <= 10^5, we use a large enough number for infinity.
    const long long INF = LLONG_MAX; 

    // Dist[r][c]: Minimum time to reach (r, c)
    std::vector<std::vector<long long>> dist(n, std::vector<long long>(m, INF));

    // FinalColor[r][c]: The resulting color
    std::vector<std::vector<long long>> finalColors(n, std::vector<long long>(m, 0));

    // Min-Priority Queue: stores {time, r, c, color}
    std::priority_queue<State, std::vector<State>, CompareState> pq;

    // 1. Initialize sources
    for (const auto& source : sources) {
        long long r = source[0];
        long long c = source[1];
        long long color = source[2];

        // Sources start at time 0
        if (dist[r][c] > 0) {
            dist[r][c] = 0;
            finalColors[r][c] = color;
            pq.push({0, r, c, color});
        }
    }

    // Directions: Up, Down, Left, Right
    long long dr[] = {-1, 1, 0, 0};
    long long dc[] = {0, 0, -1, 1};

    // 2. Modified Dijkstra/Multi-source BFS
    while (!pq.empty()) {
        State current = pq.top();
        pq.pop();

        long long t = get<0>(current);
        long long r = get<1>(current);
        long long c = get<2>(current);
        long long color = get<3>(current);

        // Optimization: Skip if this is a stale entry (a faster path was already processed)
        if (t > dist[r][c]) {
            continue;
        }

        long long newTime = t + 1;

        for (int i = 0; i < 4; ++i) {
            long long nr = r + dr[i];
            long long nc = c + dc[i];

            // Check boundaries
            if (nr >= 0 && nr < n && nc >= 0 && nc < m) {

                // Case 1: Found a strictly faster path (new time < current shortest time)
                if (newTime < dist[nr][nc]) {
                    dist[nr][nc] = newTime;
                    finalColors[nr][nc] = color;
                    pq.push({newTime, nr, nc, color});

                } 
                // Case 2: Arrived at the same minimum time (Tie resolution)
                else if (newTime == dist[nr][nc]) {
                    // Apply the color rule: take the maximum color
                    if (color > finalColors[nr][nc]) {
                        finalColors[nr][nc] = color;
                        // Note: We do not push to PQ here. The minimum time is fixed. 
                        // Updating the color doesn't change the time, so it won't affect 
                        // the subsequent neighbors' arrival times (t+2).
                    }
                }
                // Case 3: Slower path (newTime > dist[nr][nc]) -> Ignore
            }
        }
    }

    return finalColors;
}

