/**
 * A basic MinHeap implementation needed for Dijkstra's algorithm.
 * It stores elements as [priority, value1, value2, ...].
 * For this problem, priority is time.
 */
class MinPriorityQueue {
    constructor() {
        this.heap = [];
    }

    isEmpty() {
        return this.heap.length === 0;
    }

    _parent(i) { return Math.floor((i - 1) / 2); }
    _left(i) { return 2 * i + 1; }
    _right(i) { return 2 * i + 2; }

    _swap(i, j) {
        [this.heap[i], this.heap[j]] = [this.heap[j], this.heap[i]];
    }

    // Compares based on the first element (priority/time)
    _compare(i, j) {
        return this.heap[i][0] < this.heap[j][0];
    }

    enqueue(element) {
        this.heap.push(element);
        this._bubbleUp(this.heap.length - 1);
    }

    dequeue() {
        if (this.isEmpty()) return null;
        if (this.heap.length === 1) return this.heap.pop();

        const root = this.heap[0];
        this.heap[0] = this.heap.pop();
        this._bubbleDown(0);
        return root;
    }

    _bubbleUp(i) {
        let currentIndex = i;
        let parentIndex = this._parent(currentIndex);
        while (currentIndex > 0 && this._compare(currentIndex, parentIndex)) {
            this._swap(currentIndex, parentIndex);
            currentIndex = parentIndex;
            parentIndex = this._parent(currentIndex);
        }
    }

    _bubbleDown(i) {
        let currentIndex = i;
        const lastIndex = this.heap.length - 1;

        while (true) {
            let left = this._left(currentIndex);
            let right = this._right(currentIndex);
            let smallest = currentIndex;

            // Check left child
            if (left <= lastIndex && this._compare(left, smallest)) {
                smallest = left;
            }

            // Check right child
            if (right <= lastIndex && this._compare(right, smallest)) {
                smallest = right;
            }

            if (smallest !== currentIndex) {
                this._swap(currentIndex, smallest);
                currentIndex = smallest;
            } else {
                break;
            }
        }
    }
}


function solve(n, m, sources) {
    // Initialize distances (time) to infinity
    // Since N*M <= 10^5, we can use a 2D array representation.
    const INF = Infinity;
    const dist = Array(n).fill(0).map(() => Array(m).fill(INF));

    // Initialize final colors to 0 (uncolored)
    const finalColors = Array(n).fill(0).map(() => Array(m).fill(0));

    const pq = new MinPriorityQueue();
    const directions = [[0, 1], [0, -1], [1, 0], [-1, 0]];

    // 1. Initialize sources
    for (const source of sources) {
        const r = source[0];
        const c = source[1];
        const color = source[2];

        // Handle potential multiple sources at the same location (though problem constraints say they are unique)
        if (dist[r][c] > 0) {
            dist[r][c] = 0;
            finalColors[r][c] = color;
            // PQ stores: [time, r, c, color]
            pq.enqueue([0, r, c, color]);
        }
    }

    // 2. Modified Dijkstra/Multi-source BFS
    while (!pq.isEmpty()) {
        const [t, r, c, color] = pq.dequeue();

        // Optimization: If we found a strictly faster path already, skip this old entry
        if (t > dist[r][c]) {
            continue;
        }

        // If t == dist[r][c], this entry might represent a color update, 
        // but since we only proceed if the state hasn't been finalized (i.e., neighbor check), 
        // we proceed normally, knowing the color is already incorporated into finalColors[r][c]

        const newTime = t + 1;

        for (const [dr, dc] of directions) {
            const nr = r + dr;
            const nc = c + dc;

            // Check boundaries
            if (nr >= 0 && nr < n && nc >= 0 && nc < m) {

                // Case 1: Found a strictly faster path (new time < current shortest time)
                if (newTime < dist[nr][nc]) {
                    dist[nr][nc] = newTime;
                    finalColors[nr][nc] = color;
                    pq.enqueue([newTime, nr, nc, color]);

                } 
                // Case 2: Arrived at the same minimum time
                else if (newTime === dist[nr][nc]) {
                    // Apply the color rule: take the maximum color
                    if (color > finalColors[nr][nc]) {
                        finalColors[nr][nc] = color;
                        // Note: We do NOT push this state back to PQ because the minimum time
                        // for (nr, nc) is already fixed (dist[nr][nc] = newTime).
                        // Re-pushing would only lead to unnecessary processing of neighbors 
                        // at time newTime + 1 based on a potentially changed color, 
                        // but since the neighbors are only reached at time + 1, 
                        // and the time is fixed, we only need the final color recorded.
