#include <vector>
#include <queue>
#include <tuple>
#include <limits>
#include <utility>

using namespace std;

// Define the state for the Priority Queue: {time, r, c, color}
using State = tuple<long long, long long, long long, long long>; 

// Comparison structure for the Min-Heap based on time (first element)
struct CompareState {
    bool operator()(const State& a, const State& b) {
        // Return true if 'a' has lower priority than 'b' (i.e., time_a > time_b)
        return get<0>(a) > get<0>(b);
    }
};


vector<vector<long long>> solve(long long n, long long m, vector<vector<long long>> sources) {

    const long long INF = numeric_limits<long long>::max();

    // dist[r][c]: Minimum time to reach (r, c)
    vector<vector<long long>> dist(n, vector<long long>(m, INF));

    // finalColors[r][c]: Final color of (r, c)
    vector<vector<long long>> finalColors(n, vector<long long>(m, 0));

    // Min-Priority Queue: stores {time, r, c, color}
    priority_queue<State, vector<State>, CompareState> pq;

    // 1. Initialize sources
    for (const auto& source : sources) {
        long long r = source[0];
        long long c = source[1];
        long long color = source[2];

        // Initialize source nodes
        if (dist[r][c] > 0) { 
            dist[r][c] = 0;
            finalColors[r][c] = color;
            // Push: {time, r, c, color}
            pq.push({0, r, c, color});
        }
    }

    // Directions: (dr, dc) for Up, Down, Left, Right
    vector<pair<int, int>> directions = {{0, 1}, {0, -1}, {1, 0}, {-1, 0}};

    // 2. Dijkstra/Multi-source BFS
    while (!pq.empty()) {
        State current = pq.top();
        pq.pop();

        long long t = get<0>(current);
        long long r = get<1>(current);
        long long c = get<2>(current);
        long long color = get<3>(current);

        // If this entry is outdated (we found a faster path already), skip it.
        if (t > dist[r][c]) {
            continue;
        }

        // Neighbors reached at time t + 1
        long long newTime = t + 1;

        for (const auto& dir : directions) {
            long long dr = dir.first;
            long long dc = dir.second;

            long long nr = r + dr;
            long long nc = c + dc;

            // Check boundaries
            if (nr >= 0 && nr < n && nc >= 0 && nc < m) {

                // Case 1: Strictly faster path found (New minimum time)
                if (newTime < dist[nr][nc]) {
                    dist[nr][nc] = newTime;
                    finalColors[nr][nc] = color;
                    pq.push({newTime, nr, nc, color});

                } 
                // Case 2: Simultaneous arrival (Time collision)
                else if (newTime == dist[nr][nc]) {
                    // Apply the color rule: take the maximum color
                    if (color > finalColors[nr][nc]) {
                        finalColors[nr][nc] = color;
                        // Do not push to PQ, as the minimum time for (nr, nc) is already fixed.
                    }
                }
                // Case 3: Slower path (newTime > dist[nr][nc]) -> Ignore
            }
        }
    }

    return finalColors;
}

